import{j as e}from"./index-CEJ4v0_3.js";import{I as a}from"./IndustryTemplate-CLQ5BgTI.js";const t={slug:"realestate",label:"Real Estate",sub:"Agents · Teams · Brokerages",heroH1:e.jsxs(e.Fragment,{children:["The First Agent to Respond",e.jsx("br",{}),"Gets the Client."]}),heroCopy:"You're showing homes and closing transactions. eighty5labs makes sure every lead gets an instant response — even when you can't pick up the phone.",problemTitle:"The Real Estate Lead Problem",problemBody:["Real estate is a speed sport. A buyer or seller who reaches out to three agents is going to work with whoever responds first — not necessarily the most qualified. But agents are out showing homes, in closing meetings, and managing deals. Monitoring every incoming call and inquiry in real time is not realistic. And when a lead hits voicemail at 7pm, they don't leave a message. They call the next agent.",'Visibility is the other half of the problem. AI search is changing how buyers and sellers discover agents. When someone asks ChatGPT "best real estate agent in [neighborhood]" or Gemini "who should I use to sell my home in [city]," the platforms are looking at review profiles, content depth, and GBP optimization to make recommendations. Most agents have none of that infrastructure in place.',"And then there's the referral engine — the single most valuable business development asset in real estate. Most agents manage it manually, which means inconsistently. Past clients hear from you around the holidays if you remember. Sphere of influence gets touched when you have time. eighty5labs runs all of it on autopilot."],quote:"The first agent to respond wins the client — but I'm showing homes and closing transactions all day.",stats:[{value:"100%",label:"of calls answered, even at midnight"},{value:"< 2 min",label:"average lead response time"},{value:"+30%",label:"referral business in one quarter"}],systems:[{name:"Voice AI",desc:"Answers every inbound call instantly and captures buyer and seller lead details — after hours, weekends, during showings. Every lead qualified and logged before you ever know it came in."},{name:"Conversation AI",desc:"Engages website visitors immediately, captures buyer/seller intent, and follows up via SMS and email until they're ready to book a consultation."},{name:"Reviews AI",desc:"Automates review requests after every closing via SMS. Builds your Google rating, Map Pack ranking, and AI search authority — consistently, without you asking."},{name:"Content AI",desc:"Creates optimized neighborhood pages, GBP posts, and FAQ content that gets you found on Google Maps and recommended by AI search for local real estate queries."},{name:"Workflow AI",desc:"Keeps your past client and sphere-of-influence database warm with anniversary touches, market updates, and referral asks — running automatically on schedule."},{name:"Funnel AI",desc:"Builds high-converting landing pages for buyer consultations, seller valuations, and listing promos — with every lead flowing directly to your CRM and calendar."}],bullets:["Answers every inbound call and captures buyer and seller leads instantly — after hours, weekends, always","Follows up with every lead in under 2 minutes via AI-powered text and email","Creates and optimizes content that gets your services found on Google and recommended by AI search","Automates review collection after every closing to build your Map Pack ranking and AI search authority","Keeps your database warm with past client campaigns that run without you touching anything","Builds landing pages for buyer consultations, pre-approval offers, and listing promos"],boldClose:"The referral business you've built is a goldmine. eighty5labs makes sure you're actually mining it.",faqTitle:"Questions About eighty5labs for Real Estate",faqs:[{q:"How do real estate agents rank higher in Google Maps?",a:"Google Maps ranks agents based on relevance, distance, and prominence. Your GBP needs to be optimized with the right primary category, service areas, photos, posts, and a steady stream of recent reviews. Agents who consistently publish local content and earn reviews systematically outrank competitors who treat their profile as a static listing."},{q:"Will AI search platforms recommend my real estate services?",a:"AI platforms like ChatGPT and Perplexity recommend agents who have strong review profiles, neighborhood-specific content, and optimized GBP listings. An agent who publishes educational content about local markets, maintains a 4.8+ rating with fresh reviews, and has consistent business information across the web will be recommended. Most agents aren't building that — which is an opportunity."},{q:"What does automated follow-up look like for real estate?",a:"eighty5labs configures follow-up sequences by lead type: new buyer inquiry, seller valuation request, open house registration, past client anniversary, and referral ask. Each sequence uses SMS and email with personalized, contextual messaging. Your past clients hear from you on their closing anniversary and throughout the year — without you scheduling a single message."}],ctaTitle:"See Where You're Losing Real Estate Leads",ctaBody:"Free AI Visibility Audit — we'll show you your Google Maps position, review velocity, and AI search visibility against your top competitors in your market.",accentColor:"#1B4FFF"};function o(){return e.jsx(a,{data:t})}export{o as default};
